const toStr = (v) => String(v ?? '').trim();
const norm = (v) => toStr(v)
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase()
  .replace(/\s+/g, ' ')
  .trim();

const getEnv = (key) => {
  try {
    if ($env && $env[key]) return String($env[key]).trim();
  } catch (_e) {}
  try {
    const p = (typeof globalThis !== 'undefined' && globalThis.process && globalThis.process.env)
      ? globalThis.process.env[key]
      : '';
    if (p) return String(p).trim();
  } catch (_e) {}
  return '';
};

const getStore = () => {
  try {
    if (typeof $getWorkflowStaticData === 'function') return $getWorkflowStaticData('global');
  } catch (_e) {}
  try {
    if (this && typeof this.getWorkflowStaticData === 'function') return this.getWorkflowStaticData('global');
  } catch (_e) {}
  const root = (typeof globalThis !== 'undefined') ? globalThis : {};
  if (!root.__frChatFallbackStore) root.__frChatFallbackStore = {};
  return root.__frChatFallbackStore;
};

const raw = $json || {};

const deepFindMessage = (obj) => {
  const exactKeys = new Set(['chatInput', 'message', 'text', 'input']);

  const direct = [
    obj?.chatInput,
    obj?.message,
    obj?.text,
    obj?.input,
    obj?.body?.chatInput,
    obj?.body?.message,
    obj?.body?.text,
    obj?.body?.input,
    obj?.payload?.chatInput,
    obj?.payload?.message,
    obj?.payload?.text,
    obj?.payload?.input,
    obj?.data?.chatInput,
    obj?.data?.message,
    obj?.data?.text,
    obj?.data?.input,
  ];
  for (const c of direct) {
    const s = toStr(c);
    if (s) return s;
  }

  const queue = [obj];
  const seen = new Set();
  while (queue.length) {
    const cur = queue.shift();
    if (!cur || typeof cur !== 'object') continue;
    if (seen.has(cur)) continue;
    seen.add(cur);
    for (const [k, v] of Object.entries(cur)) {
      if (typeof v === 'string' && exactKeys.has(String(k))) {
        const s = toStr(v);
        if (s) return s;
      } else if (v && typeof v === 'object') {
        queue.push(v);
      }
    }
  }

  return '';
};

const message = deepFindMessage(raw);
const sessionId = toStr(
  raw.chatId ||
  raw.chat_id ||
  raw.conversationId ||
  raw.conversation_id ||
  raw.metadata?.chatId ||
  raw.metadata?.chat_id ||
  raw.metadata?.conversationId ||
  raw.metadata?.conversation_id ||
  raw.sessionId ||
  raw.session_id ||
  raw.chatSessionId ||
  raw.metadata?.sessionId ||
  'default'
);
// Estado de conversa: usar chave global para evitar perda quando o chat provider troca session_id por mensagem.
const stateKey = 'global_chat_state';

const store = getStore();
if (!store.chatMemoryBySession) store.chatMemoryBySession = {};
if (!store.modeBySession) store.modeBySession = {};
if (!store.menuShownBySession) store.menuShownBySession = {};
if (!store.impactIntakeBySession) store.impactIntakeBySession = {};

if (!Array.isArray(store.chatMemoryBySession[stateKey])) {
  store.chatMemoryBySession[stateKey] = [];
}

const pushMemory = (role, content) => {
  const text = toStr(content);
  if (!text) return;
  store.chatMemoryBySession[stateKey].push({ role, content: text, at: new Date().toISOString() });
  if (store.chatMemoryBySession[stateKey].length > 40) {
    store.chatMemoryBySession[stateKey] = store.chatMemoryBySession[stateKey].slice(-40);
  }
};

const chatHistory = () =>
  store.chatMemoryBySession[stateKey]
    .slice(-12)
    .map((t) => ({ role: t.role, content: toStr(t.content) }));

const menuText = [
  'Escolha uma opcao para continuar (envie apenas 1, 2 ou 3):',
  '1) Nova analise de Impacto',
  '2) Duvida sobre funcionalidade ja implementada',
  '3) Correcao de PRs abertas',
  '',
  'Comandos uteis:',
  '/menu: voltar ao menu',
  '/reset: limpar estado da conversa'
].join('\n');

const questions = [
  { field: 'problema', text: 'Qual problema ou oportunidade essa alteracao resolve?' },
  { field: 'mudanca', text: 'Descreva a mudanca como voce espera ver no produto.' },
  { field: 'evidencias', text: 'Quais evidencias/criterios de aceite comprovam que a entrega esta pronta? (lista: uma por linha, ou separadas por ";")' },
  { field: 'restricoes', text: 'Limites de prazo, compliance, integracoes proibidas, etc. (lista: uma por linha, ou separadas por ";")' },
];
const questionNorms = questions.map((q) => norm(q.text));

const emptyIntake = () => ({
  step: 0,
  problema: '',
  mudanca: '',
  evidencias: [],
  restricoes: [],
  status: '',
  diagnostico: '',
  evidencias_lista: [],
});

const askQuestion = (step) => {
  const idx = Math.max(0, Math.min(Number(step || 0), questions.length - 1));
  return questions[idx].text;
};

const parseList = (input) =>
  toStr(input)
    .split(/\n|;|\|/g)
    .map((s) => toStr(s).replace(/^[-*\d.)\s]+/, ''))
    .filter(Boolean);

const inferLastAskedStepFromRaw = (obj) => {
  let blob = '';
  try { blob = norm(JSON.stringify(obj || {})); } catch (_e) { blob = ''; }
  if (!blob) return -1;
  let last = -1;
  for (let i = 0; i < questionNorms.length; i++) {
    if (blob.includes(questionNorms[i])) last = i;
  }
  return last;
};

const resetSession = () => {
  delete store.modeBySession[stateKey];
  delete store.impactIntakeBySession[stateKey];
  store.menuShownBySession[stateKey] = true;
};

const currentMode = toStr(store.modeBySession[stateKey] || '');

if (!message) {
  store.menuShownBySession[stateKey] = true;
  const output = menuText;
  pushMemory('assistant', output);
  return [{ json: { option: 'invalid', route: 'impact_collect_question', session_id: sessionId, chat_history: chatHistory(), output } }];
}

const lower = norm(message);
if (lower === '/reset' || lower === '/menu') {
  resetSession();
  const output = menuText;
  pushMemory('assistant', output);
  return [{ json: { option: 'invalid', route: 'impact_collect_question', session_id: sessionId, chat_history: chatHistory(), output } }];
}

pushMemory('user', message);

const optionMatch = toStr(message).match(/^\s*([123])\s*$/);

// Primeira interacao: mostra menu apenas quando nao for opcao valida.
if (!store.menuShownBySession[stateKey] && !currentMode && !optionMatch) {
  store.menuShownBySession[stateKey] = true;
  const output = menuText;
  pushMemory('assistant', output);
  return [{ json: { option: 'invalid', route: 'impact_collect_question', session_id: sessionId, chat_history: chatHistory(), output } }];
}

if (currentMode === 'impact_intake') {
  const state = store.impactIntakeBySession[stateKey] || emptyIntake();
  const idx = Math.max(0, Math.min(Number(state.step || 0), questions.length - 1));
  const field = questions[idx].field;

  if (field === 'evidencias' || field === 'restricoes') state[field] = parseList(message);
  else state[field] = toStr(message);

  state.step = idx + 1;

  if (state.step >= questions.length) {
    const evidenciasLista = Array.isArray(state.evidencias) ? state.evidencias : [];
    const restricoesLista = Array.isArray(state.restricoes) ? state.restricoes : [];

    delete store.modeBySession[stateKey];
    delete store.impactIntakeBySession[stateKey];

    return [{
      json: {
        option: '1',
        route: 'impact_ready',
        ready_for_impact: true,
        session_id: sessionId,
        chat_history: chatHistory(),
        problema: toStr(state.problema),
        mudanca: toStr(state.mudanca),
        evidencias: evidenciasLista.join('; '),
        restricoes: restricoesLista.join('; '),
        status: toStr(state.status),
        diagnostico: toStr(state.diagnostico),
        evidencias_lista: evidenciasLista,
        restricoes_lista: restricoesLista,
      }
    }];
  }

  store.impactIntakeBySession[stateKey] = state;
  const output = askQuestion(state.step);
  pushMemory('assistant', output);
  return [{ json: { option: '1', route: 'impact_collect_question', session_id: sessionId, chat_history: chatHistory(), output } }];
}

if (currentMode === 'pr_qa') {
  return [{
    json: {
      option: '2',
      route: 'pr_qa',
      session_id: sessionId,
      chat_history: chatHistory(),
      question: message,
      owner: toStr(getEnv('GITHUB_OWNER') || 'oliversoft-tech'),
      github_token: toStr(getEnv('GITHUB_TOKEN') || ''),
      llm_model: toStr(getEnv('LLM_MODEL') || 'claude-3-5-sonnet-20241022')
    }
  }];
}

if (currentMode === 'correction_propose') {
  return [{
    json: {
      option: '3',
      route: 'correction_propose',
      session_id: sessionId,
      chat_history: chatHistory(),
      question: message,
      owner: toStr(getEnv('GITHUB_OWNER') || 'oliversoft-tech'),
      github_token: toStr(getEnv('GITHUB_TOKEN') || ''),
      llm_model: toStr(getEnv('LLM_MODEL') || 'claude-3-5-sonnet-20241022')
    }
  }];
}

// Fallback sem memoria persistida: infere a pergunta atual pelo payload.
if (!currentMode && !optionMatch) {
  const inferredStep = inferLastAskedStepFromRaw(raw);
  if (inferredStep >= 0) {
    const st = store.impactIntakeBySession[stateKey] || emptyIntake();
    const idx = Math.max(0, Math.min(inferredStep, questions.length - 1));
    const field = questions[idx].field;
    if (field === 'evidencias' || field === 'restricoes') st[field] = parseList(message);
    else st[field] = toStr(message);
    st.step = idx + 1;

    if (st.step >= questions.length) {
      const evidenciasLista = Array.isArray(st.evidencias) ? st.evidencias : [];
      const restricoesLista = Array.isArray(st.restricoes) ? st.restricoes : [];
      delete store.modeBySession[stateKey];
      delete store.impactIntakeBySession[stateKey];
      return [{
        json: {
          option: '1',
          route: 'impact_ready',
          ready_for_impact: true,
          session_id: sessionId,
          chat_history: chatHistory(),
          problema: toStr(st.problema),
          mudanca: toStr(st.mudanca),
          evidencias: evidenciasLista.join('; '),
          restricoes: restricoesLista.join('; '),
          status: toStr(st.status),
          diagnostico: toStr(st.diagnostico),
          evidencias_lista: evidenciasLista,
          restricoes_lista: restricoesLista,
        }
      }];
    }

    store.modeBySession[stateKey] = 'impact_intake';
    store.impactIntakeBySession[stateKey] = st;
    const output = askQuestion(st.step);
    pushMemory('assistant', output);
    return [{ json: { option: '1', route: 'impact_collect_question', session_id: sessionId, chat_history: chatHistory(), output } }];
  }
}

if (!optionMatch) {
  const output = 'Opcao invalida! Escolha 1, 2 ou 3.\n\n' + menuText;
  pushMemory('assistant', output);
  return [{ json: { option: 'invalid', route: 'impact_collect_question', session_id: sessionId, chat_history: chatHistory(), output } }];
}

const opt = optionMatch[1];
if (opt === '1') {
  store.modeBySession[stateKey] = 'impact_intake';
  const st = emptyIntake();
  store.impactIntakeBySession[stateKey] = st;
  const output = askQuestion(0);
  pushMemory('assistant', output);
  return [{ json: { option: '1', route: 'impact_collect_question', session_id: sessionId, chat_history: chatHistory(), output } }];
}

if (opt === '2') {
  store.modeBySession[stateKey] = 'pr_qa';
  const output = 'Opcao 2 selecionada. Agora descreva sua duvida sobre funcionalidade ja implementada.';
  pushMemory('assistant', output);
  return [{ json: { option: '2', route: 'impact_collect_question', session_id: sessionId, chat_history: chatHistory(), output } }];
}

store.modeBySession[stateKey] = 'correction_propose';
const output = 'Opcao 3 selecionada. Agora descreva a correcao desejada nas PRs abertas.';
pushMemory('assistant', output);
return [{ json: { option: '3', route: 'impact_collect_question', session_id: sessionId, chat_history: chatHistory(), output } }];
